+package segments
+
+type Gcc struct {
+	Language
+}
+
+const gccToolName string = "gcc"
+
+func (gcc *Gcc) Enabled() bool {
+	gcc.extensions = []string{"*.c", "*.cpp", "*.h", "CMakeLists.txt"}
+	gcc.defaultTooling = []string{gccToolName}
